def solve(nums: Array[Long], k: Long): Long = {
    val n = nums.length
    val prefixXOR = Array.ofDim[Long](n + 1)
    prefixXOR(0) = 0
    for (i <- 0 until n) {
        prefixXOR(i + 1) = prefixXOR(i) ^ nums(i)
    }

    val dp = Array.ofDim[Long](n + 1)(k + 1)
    for (i <- 0 to n) {
        for (j <- 0 to k) {
            dp(i)(j) = Long.MaxValue
        }
    }
    dp(0)(0) = 0

    for (i <- 1 to n) {
        for (j <- 1 to k) {
            for (m <- 0 until i) {
                val currentMax = Math.max(dp(m)(j - 1), prefixXOR(i) ^ prefixXOR(m))
                if (currentMax < dp(i)(j)) {
                    dp(i)(j) = currentMax
                }
            }
        }
    }

    dp(n)(k)
}
